//! Launch Interceptor Program — DECIDE (Knight & Leveson, 1986).

use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

/// Compare two reals using six significant digits (per spec.md).
pub fn realcompare(a: f64, b: f64) -> &'static str {
    fn round6(x: f64) -> f64 {
        if x == 0.0 {
            return 0.0;
        }
        if !x.is_finite() {
            return x;
        }
        let sign = x.signum();
        let ax = x.abs();
        let exp = ax.log10().floor() as i32;
        let factor = 10_f64.powi(5 - exp);
        sign * (ax * factor).round() / factor
    }
    let ra = round6(a);
    let rb = round6(b);
    if ra < rb {
        "LT"
    } else if ra > rb {
        "GT"
    } else {
        "EQ"
    }
}

fn cmp_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "LT"
}

fn cmp_le(a: f64, b: f64) -> bool {
    matches!(realcompare(a, b), "LT" | "EQ")
}

fn cmp_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "GT"
}

fn cmp_ge(a: f64, b: f64) -> bool {
    matches!(realcompare(a, b), "GT" | "EQ")
}

fn dist(x0: f64, y0: f64, x1: f64, y1: f64) -> f64 {
    let dx = x1 - x0;
    let dy = y1 - y0;
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(x0: f64, y0: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x0 * (y1 - y2) + x1 * (y2 - y0) + x2 * (y0 - y1)) * 0.5).abs()
}

/// Minimum radius of a circle that contains three points (degenerate: half longest segment).
fn min_enclosing_circle_radius_3(
    ax: f64,
    ay: f64,
    bx: f64,
    by: f64,
    cx: f64,
    cy: f64,
) -> f64 {
    let ab = dist(ax, ay, bx, by);
    let bc = dist(bx, by, cx, cy);
    let ca = dist(cx, cy, ax, ay);

    let cross = (bx - ax) * (cy - ay) - (by - ay) * (cx - ax);
    if realcompare(cross.abs(), 0.0) == "EQ" {
        // Collinear: smallest enclosing circle has diameter = longest edge
        return ab.max(bc).max(ca) * 0.5;
    }

    let area = triangle_area(ax, ay, bx, by, cx, cy);
    let circum_r = (ab * bc * ca) / (4.0 * area);

    // Obtuse triangle: smallest enclosing circle has the longest side as diameter
    let dot_c = (ax - cx) * (bx - cx) + (ay - cy) * (by - cy);
    if cmp_lt(dot_c, 0.0) {
        return ab * 0.5;
    }
    let dot_a = (bx - ax) * (cx - ax) + (by - ay) * (cy - ay);
    if cmp_lt(dot_a, 0.0) {
        return bc * 0.5;
    }
    let dot_b = (ax - bx) * (cx - bx) + (ay - by) * (cy - by);
    if cmp_lt(dot_b, 0.0) {
        return ca * 0.5;
    }

    circum_r
}

fn point_to_line_dist(px: f64, py: f64, ax: f64, ay: f64, bx: f64, by: f64) -> f64 {
    let abx = bx - ax;
    let aby = by - ay;
    let apx = px - ax;
    let apy = py - ay;
    let len = (abx * abx + aby * aby).sqrt();
    if cmp_le(len, 0.0) {
        return dist(px, py, ax, ay);
    }
    (abx * apy - aby * apx).abs() / len
}

fn quadrant(x: f64, y: f64) -> u8 {
    if realcompare(x, 0.0) == "EQ" {
        if realcompare(y, 0.0) == "EQ" {
            1
        } else if cmp_gt(y, 0.0) {
            1
        } else {
            3
        }
    } else if cmp_lt(x, 0.0) {
        if cmp_ge(y, 0.0) {
            2
        } else {
            3
        }
    } else if cmp_ge(y, 0.0) {
        1
    } else {
        4
    }
}

fn lic1(input: &DecideInput) -> bool {
    let p = &input.parameters;
    for i in 0..input.numpoints.saturating_sub(1) {
        let d = dist(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if cmp_gt(d, p.length1) {
            return true;
        }
    }
    false
}

fn lic2(input: &DecideInput) -> bool {
    let p = &input.parameters;
    for i in 0..input.numpoints.saturating_sub(2) {
        let r = min_enclosing_circle_radius_3(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if cmp_gt(r, p.radius1) {
            return true;
        }
    }
    false
}

fn lic3(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let eps = p.epsilon;
    for i in 0..input.numpoints.saturating_sub(2) {
        let x1 = input.x[i];
        let y1 = input.y[i];
        let vx = input.x[i + 1];
        let vy = input.y[i + 1];
        let x3 = input.x[i + 2];
        let y3 = input.y[i + 2];
        if realcompare(x1, vx) == "EQ" && realcompare(y1, vy) == "EQ" {
            continue;
        }
        if realcompare(x3, vx) == "EQ" && realcompare(y3, vy) == "EQ" {
            continue;
        }
        let v1x = x1 - vx;
        let v1y = y1 - vy;
        let v2x = x3 - vx;
        let v2y = y3 - vy;
        let n1 = (v1x * v1x + v1y * v1y).sqrt();
        let n2 = (v2x * v2x + v2y * v2y).sqrt();
        if cmp_le(n1, 0.0) || cmp_le(n2, 0.0) {
            continue;
        }
        let c = (v1x * v2x + v1y * v2y) / (n1 * n2);
        let c = c.clamp(-1.0, 1.0);
        let angle = c.acos();
        let low = PI - eps;
        let high = PI + eps;
        if cmp_lt(angle, low) || cmp_gt(angle, high) {
            return true;
        }
    }
    false
}

fn lic4(input: &DecideInput) -> bool {
    let p = &input.parameters;
    for i in 0..input.numpoints.saturating_sub(2) {
        let a = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if cmp_gt(a, p.area1) {
            return true;
        }
    }
    false
}

fn lic5(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let q = p.q_pts;
    if q < 2 || q > input.numpoints {
        return false;
    }
    for start in 0..=input.numpoints - q {
        let mut seen = [false; 5];
        for k in 0..q {
            let idx = start + k;
            let qn = quadrant(input.x[idx], input.y[idx]);
            seen[qn as usize] = true;
        }
        let mut count = 0u8;
        for s in 1..=4 {
            if seen[s as usize] {
                count += 1;
            }
        }
        if count as usize > p.quads {
            return true;
        }
    }
    false
}

fn lic6(input: &DecideInput) -> bool {
    for i in 0..input.numpoints.saturating_sub(1) {
        let dx = input.x[i + 1] - input.x[i];
        if cmp_lt(dx, 0.0) {
            return true;
        }
    }
    false
}

fn lic7(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let p = &input.parameters;
    let n = p.n_pts;
    if n < 3 || n > input.numpoints {
        return false;
    }
    for start in 0..=input.numpoints - n {
        let ax = input.x[start];
        let ay = input.y[start];
        let bx = input.x[start + n - 1];
        let by = input.y[start + n - 1];
        let coincident = realcompare(ax, bx) == "EQ" && realcompare(ay, by) == "EQ";
        let mut any = false;
        for k in 1..(n - 1) {
            let idx = start + k;
            let d = if coincident {
                dist(input.x[idx], input.y[idx], ax, ay)
            } else {
                point_to_line_dist(input.x[idx], input.y[idx], ax, ay, bx, by)
            };
            if cmp_gt(d, p.dist) {
                any = true;
                break;
            }
        }
        if any {
            return true;
        }
    }
    false
}

fn lic8(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let p = &input.parameters;
    let k = p.k_pts;
    let gap = k + 1;
    for i in 0..input.numpoints {
        let j = i + gap;
        if j >= input.numpoints {
            break;
        }
        let d = dist(input.x[i], input.y[i], input.x[j], input.y[j]);
        if cmp_gt(d, p.length1) {
            return true;
        }
    }
    false
}

fn lic9(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let p = &input.parameters;
    let a = p.a_pts;
    let b = p.b_pts;
    let span = a + b + 2;
    for i in 0..input.numpoints {
        let i1 = i + a + 1;
        let i2 = i + span;
        if i2 >= input.numpoints {
            break;
        }
        let r = min_enclosing_circle_radius_3(
            input.x[i],
            input.y[i],
            input.x[i1],
            input.y[i1],
            input.x[i2],
            input.y[i2],
        );
        if cmp_gt(r, p.radius1) {
            return true;
        }
    }
    false
}

fn lic10(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let p = &input.parameters;
    let c = p.c_pts;
    let d = p.d_pts;
    let span = c + d + 2;
    let eps = p.epsilon;
    for i in 0..input.numpoints {
        let i1 = i + c + 1;
        let i2 = i + span;
        if i2 >= input.numpoints {
            break;
        }
        let x1 = input.x[i];
        let y1 = input.y[i];
        let vx = input.x[i1];
        let vy = input.y[i1];
        let x3 = input.x[i2];
        let y3 = input.y[i2];
        if realcompare(x1, vx) == "EQ" && realcompare(y1, vy) == "EQ" {
            continue;
        }
        if realcompare(x3, vx) == "EQ" && realcompare(y3, vy) == "EQ" {
            continue;
        }
        let v1x = x1 - vx;
        let v1y = y1 - vy;
        let v2x = x3 - vx;
        let v2y = y3 - vy;
        let n1 = (v1x * v1x + v1y * v1y).sqrt();
        let n2 = (v2x * v2x + v2y * v2y).sqrt();
        if cmp_le(n1, 0.0) || cmp_le(n2, 0.0) {
            continue;
        }
        let cosv = (v1x * v2x + v1y * v2y) / (n1 * n2);
        let cosv = cosv.clamp(-1.0, 1.0);
        let angle = cosv.acos();
        let low = PI - eps;
        let high = PI + eps;
        if cmp_lt(angle, low) || cmp_gt(angle, high) {
            return true;
        }
    }
    false
}

fn lic11(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let p = &input.parameters;
    let e = p.e_pts;
    let f = p.f_pts;
    let span = e + f + 2;
    for i in 0..input.numpoints {
        let i1 = i + e + 1;
        let i2 = i + span;
        if i2 >= input.numpoints {
            break;
        }
        let a = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i1],
            input.y[i1],
            input.x[i2],
            input.y[i2],
        );
        if cmp_gt(a, p.area1) {
            return true;
        }
    }
    false
}

fn lic12(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let g = input.parameters.g_pts;
    let gap = g + 1;
    for i in 0..input.numpoints {
        let j = i + gap;
        if j >= input.numpoints {
            break;
        }
        let dx = input.x[j] - input.x[i];
        if cmp_lt(dx, 0.0) {
            return true;
        }
    }
    false
}

fn lic13(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let p = &input.parameters;
    let k = p.k_pts;
    let gap = k + 1;
    let mut gt_l1 = false;
    let mut lt_l2 = false;
    for i in 0..input.numpoints {
        let j = i + gap;
        if j >= input.numpoints {
            break;
        }
        let d = dist(input.x[i], input.y[i], input.x[j], input.y[j]);
        if cmp_gt(d, p.length1) {
            gt_l1 = true;
        }
        if cmp_lt(d, p.length2) {
            lt_l2 = true;
        }
        if gt_l1 && lt_l2 {
            return true;
        }
    }
    false
}

fn lic14(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let p = &input.parameters;
    let a = p.a_pts;
    let b = p.b_pts;
    let span = a + b + 2;
    let mut cannot_r1 = false;
    let mut fits_r2 = false;
    for i in 0..input.numpoints {
        let i1 = i + a + 1;
        let i2 = i + span;
        if i2 >= input.numpoints {
            break;
        }
        let r = min_enclosing_circle_radius_3(
            input.x[i],
            input.y[i],
            input.x[i1],
            input.y[i1],
            input.x[i2],
            input.y[i2],
        );
        if cmp_gt(r, p.radius1) {
            cannot_r1 = true;
        }
        if cmp_le(r, p.radius2) {
            fits_r2 = true;
        }
        if cannot_r1 && fits_r2 {
            return true;
        }
    }
    false
}

fn lic15(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let p = &input.parameters;
    let e = p.e_pts;
    let f = p.f_pts;
    let span = e + f + 2;
    let mut gt_a1 = false;
    let mut lt_a2 = false;
    for i in 0..input.numpoints {
        let i1 = i + e + 1;
        let i2 = i + span;
        if i2 >= input.numpoints {
            break;
        }
        let area = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i1],
            input.y[i1],
            input.x[i2],
            input.y[i2],
        );
        if cmp_gt(area, p.area1) {
            gt_a1 = true;
        }
        if cmp_lt(area, p.area2) {
            lt_a2 = true;
        }
        if gt_a1 && lt_a2 {
            return true;
        }
    }
    false
}

fn compute_cmv(input: &DecideInput) -> Vec<bool> {
    vec![
        lic1(input),
        lic2(input),
        lic3(input),
        lic4(input),
        lic5(input),
        lic6(input),
        lic7(input),
        lic8(input),
        lic9(input),
        lic10(input),
        lic11(input),
        lic12(input),
        lic13(input),
        lic14(input),
        lic15(input),
    ]
}

fn compute_pum(input: &DecideInput, cmv: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            let op = match input.lcm[i][j].as_str() {
                "NOTUSED" => "NOTUSED",
                "ORR" => "ORR",
                "ANDD" => "ANDD",
                _ => "NOTUSED",
            };
            let ci = cmv[i];
            let cj = cmv[j];
            pum[i][j] = match op {
                "NOTUSED" => true,
                "ANDD" => ci && cj,
                "ORR" => ci || cj,
                _ => true,
            };
        }
    }
    pum
}

fn compute_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
            continue;
        }
        let all_true = (0..15).all(|j| pum[i][j]);
        fuv[i] = all_true;
    }
    fuv
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let cmv = compute_cmv(input);
    let pum = compute_pum(input, &cmv);
    let fuv = compute_fuv(&pum);
    let launch = (0..15).all(|i| fuv[i]);
    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
